from flask import Flask, request, jsonify
from pymemcache.client import base
from sqlalchemy import create_engine, text
from datetime import timedelta


app = Flask(__name__)

db = create_engine('sqlite:///test.db')

memcached_client = base.Client(('localhost', 11211))

@app.route('/api/data', methods=['GET'])
def get_data():
    key = 'api/data'
    response = memcached_client.get(key)
    
    if response is None:
        stmt = text("SELECT * FROM data")
        result = db.engine.execute(stmt)
        result = [dict(row) for row in result]
        response = jsonify(result)
        memcached_client.set(key, response, expire=60)
    
    return response

@app.route('/api/query', methods=['POST'])
def query():
    data = request.get_json()
    key = 'api/query:' + data.get('query', '')
    response = memcached_client.get(key)
    
    if response is None:
        stmt = text(data['query'])
        result = db.engine.execute(stmt)
        result = [dict(row) for row in result]
        response = jsonify(result)
        memcached_client.set(key, response, timedelta(minutes=30))
    
    return response


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)